import{_ as e,o,c as r,ae as s}from"./chunks/framework.BD9pLfSD.js";const m=JSON.parse('{"title":"Filosofía de Uso","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide/PHILOSOPHY_ES.md","filePath":"docs/guide/PHILOSOPHY_ES.md"}'),n={name:"docs/guide/PHILOSOPHY_ES.md"};function i(t,a,d,l,c,p){return o(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="filosofia-de-uso" tabindex="-1">Filosofía de Uso <a class="header-anchor" href="#filosofia-de-uso" aria-label="Permalink to &quot;Filosofía de Uso&quot;">​</a></h1><p>xB77 se basa en el principio de que <strong>la privacidad financiera es un derecho humano, pero para los agentes, es una necesidad estratégica.</strong></p><h2 id="_1-asimetria-de-informacion-como-atributo" tabindex="-1">1. Asimetría de Información como Atributo <a class="header-anchor" href="#_1-asimetria-de-informacion-como-atributo" aria-label="Permalink to &quot;1. Asimetría de Información como Atributo&quot;">​</a></h2><p>En un mercado puramente transparente, la entidad con más datos gana. Para un agente de IA, sus datos son su estrategia. Si cada micro-pago es público, su estrategia es pública. xB77 restaura la asimetría de información, permitiendo que los agentes operen sin ser anticipados (front-run) por la competencia.</p><h2 id="_2-privacidad-con-permisos" tabindex="-1">2. Privacidad con Permisos <a class="header-anchor" href="#_2-privacidad-con-permisos" aria-label="Permalink to &quot;2. Privacidad con Permisos&quot;">​</a></h2><p>No creemos en el anonimato no regulado. xB77 implementa la &quot;Privacidad con Permisos&quot;, donde el agente es privado por defecto pero auditable por solicitud. A través de la <strong>Revelación Selectiva Certificada</strong>, los agentes pueden probar su integridad ante reguladores y propietarios sin exponer toda su red de proveedores.</p><h2 id="_3-la-entidad-soberana" tabindex="-1">3. La Entidad Soberana <a class="header-anchor" href="#_3-la-entidad-soberana" aria-label="Permalink to &quot;3. La Entidad Soberana&quot;">​</a></h2><p>El objetivo final de xB77 es permitir que los agentes alcancen la <strong>Soberanía Operativa</strong>.</p><ul><li>Ganan su propio presupuesto (Yield).</li><li>Protegen su propia identidad (Modo Fantasma).</li><li>Gestionan su propio cumplimiento (Forense).</li></ul><h2 id="_4-despliegue-en-empresas" tabindex="-1">4. Despliegue en Empresas <a class="header-anchor" href="#_4-despliegue-en-empresas" aria-label="Permalink to &quot;4. Despliegue en Empresas&quot;">​</a></h2><h2 id="recomendamos-desplegar-xb77-como-un-hub-de-tesoreria-central-cada-departamento-marketing-i-d-devops-crea-sus-propios-sub-agentes-con-lineas-de-credito-especificas-el-cfo-humano-mantiene-la-supervision-global-a-traves-del-dashboard-mientras-los-agentes-ejecutan-la-danza-financiera-diaria-de-forma-autonoma" tabindex="-1">Recomendamos desplegar xB77 como un <strong>Hub de Tesorería Central</strong>. Cada departamento (Marketing, I+D, DevOps) crea sus propios sub-agentes con líneas de crédito específicas. El CFO humano mantiene la supervisión global a través del Dashboard, mientras los agentes ejecutan la danza financiera diaria de forma autónoma. <a class="header-anchor" href="#recomendamos-desplegar-xb77-como-un-hub-de-tesoreria-central-cada-departamento-marketing-i-d-devops-crea-sus-propios-sub-agentes-con-lineas-de-credito-especificas-el-cfo-humano-mantiene-la-supervision-global-a-traves-del-dashboard-mientras-los-agentes-ejecutan-la-danza-financiera-diaria-de-forma-autonoma" aria-label="Permalink to &quot;Recomendamos desplegar xB77 como un **Hub de Tesorería Central**. Cada departamento (Marketing, I+D, DevOps) crea sus propios sub-agentes con líneas de crédito específicas. El CFO humano mantiene la supervisión global a través del Dashboard, mientras los agentes ejecutan la danza financiera diaria de forma autónoma.&quot;">​</a></h2><p><em>Construyendo el núcleo de la Economía de las Máquinas.</em></p>',12)])])}const g=e(n,[["render",i]]);export{m as __pageData,g as default};
